/**
 * Advanced Example Module Events
 *
 * Event definitions and emitters demonstrating E-Menum event patterns.
 * This file showcases:
 * - Typed event payloads
 * - Event emitter helper functions
 * - Event constants
 * - Event listener registration
 *
 * @module modules/_examples/advanced-example/events
 *
 * @example
 * ```typescript
 * import {
 *   emitExampleCreated,
 *   ADVANCED_EXAMPLE_EVENTS,
 * } from '@/modules/_examples/advanced-example/advanced-example.events';
 *
 * // Emit an event
 * await emitExampleCreated(eventService, {
 *   exampleId: 'ex_123',
 *   organizationId: 'org_456',
 *   name: 'My Example',
 *   status: ExampleStatus.DRAFT,
 * });
 * ```
 */

import type { EventService } from '@/core/services/event.service';

import type {
  ExampleStatus,
  BaseEventPayload,
  ExampleCreatedEventPayload,
  ExampleUpdatedEventPayload,
  ExampleDeletedEventPayload,
  ExampleStatusChangedEventPayload,
  ExampleProcessedEventPayload,
} from '@/modules/_examples/advanced-example/advanced-example.types';

// -----------------------------------------------------------------------------
// Event Names
// -----------------------------------------------------------------------------

/**
 * Advanced Example module event names
 */
export const ADVANCED_EXAMPLE_EVENTS = {
  // Core CRUD events
  CREATED: 'advanced-example.created',
  UPDATED: 'advanced-example.updated',
  DELETED: 'advanced-example.deleted',

  // Status events
  STATUS_CHANGED: 'advanced-example.status.changed',

  // Processing events
  PROCESSED: 'advanced-example.processed',
  PROCESS_STARTED: 'advanced-example.process.started',
  PROCESS_COMPLETED: 'advanced-example.process.completed',
  PROCESS_FAILED: 'advanced-example.process.failed',

  // Item events
  ITEM_CREATED: 'advanced-example.item.created',
  ITEM_UPDATED: 'advanced-example.item.updated',
  ITEM_DELETED: 'advanced-example.item.deleted',

  // Bulk events
  BULK_OPERATION: 'advanced-example.bulk.operation',
} as const;

/**
 * Event name type
 */
export type AdvancedExampleEventName = (typeof ADVANCED_EXAMPLE_EVENTS)[keyof typeof ADVANCED_EXAMPLE_EVENTS];

/**
 * All event names as an array
 */
export const ALL_EXAMPLE_EVENTS: AdvancedExampleEventName[] = Object.values(ADVANCED_EXAMPLE_EVENTS);

// -----------------------------------------------------------------------------
// Additional Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Item created event payload
 */
export interface ItemCreatedEventPayload extends BaseEventPayload {
  /** Item ID */
  itemId: string;
  /** Example ID */
  exampleId: string;
  /** Item name */
  name: string;
}

/**
 * Item updated event payload
 */
export interface ItemUpdatedEventPayload extends BaseEventPayload {
  /** Item ID */
  itemId: string;
  /** Example ID */
  exampleId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
}

/**
 * Item deleted event payload
 */
export interface ItemDeletedEventPayload extends BaseEventPayload {
  /** Item ID */
  itemId: string;
  /** Example ID */
  exampleId: string;
}

/**
 * Bulk operation event payload
 */
export interface BulkOperationEventPayload extends BaseEventPayload {
  /** Operation type */
  operation: 'delete' | 'archive' | 'activate' | 'deactivate';
  /** Affected IDs */
  ids: string[];
  /** Number of affected items */
  affected: number;
}

/**
 * Process started event payload
 */
export interface ProcessStartedEventPayload extends BaseEventPayload {
  /** Example ID */
  exampleId: string;
  /** Processing options */
  options?: Record<string, unknown>;
}

// -----------------------------------------------------------------------------
// Events Map
// -----------------------------------------------------------------------------

/**
 * Advanced Example module events map
 */
export interface AdvancedExampleModuleEvents {
  // Core CRUD
  [ADVANCED_EXAMPLE_EVENTS.CREATED]: ExampleCreatedEventPayload;
  [ADVANCED_EXAMPLE_EVENTS.UPDATED]: ExampleUpdatedEventPayload;
  [ADVANCED_EXAMPLE_EVENTS.DELETED]: ExampleDeletedEventPayload;

  // Status
  [ADVANCED_EXAMPLE_EVENTS.STATUS_CHANGED]: ExampleStatusChangedEventPayload;

  // Processing
  [ADVANCED_EXAMPLE_EVENTS.PROCESSED]: ExampleProcessedEventPayload;
  [ADVANCED_EXAMPLE_EVENTS.PROCESS_STARTED]: ProcessStartedEventPayload;
  [ADVANCED_EXAMPLE_EVENTS.PROCESS_COMPLETED]: ExampleProcessedEventPayload;
  [ADVANCED_EXAMPLE_EVENTS.PROCESS_FAILED]: ExampleProcessedEventPayload;

  // Items
  [ADVANCED_EXAMPLE_EVENTS.ITEM_CREATED]: ItemCreatedEventPayload;
  [ADVANCED_EXAMPLE_EVENTS.ITEM_UPDATED]: ItemUpdatedEventPayload;
  [ADVANCED_EXAMPLE_EVENTS.ITEM_DELETED]: ItemDeletedEventPayload;

  // Bulk
  [ADVANCED_EXAMPLE_EVENTS.BULK_OPERATION]: BulkOperationEventPayload;
}

// -----------------------------------------------------------------------------
// Helper Functions
// -----------------------------------------------------------------------------

/**
 * Creates a timestamp string
 */
function timestamp(): string {
  return new Date().toISOString();
}

/**
 * Emits an example created event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload (without timestamp)
 *
 * @example
 * ```typescript
 * await emitExampleCreated(eventService, {
 *   exampleId: 'ex_123',
 *   organizationId: 'org_456',
 *   name: 'My Example',
 *   status: ExampleStatus.DRAFT,
 * });
 * ```
 */
export async function emitExampleCreated(
  eventService: EventService,
  payload: Omit<ExampleCreatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.CREATED, {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an example updated event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload
 */
export async function emitExampleUpdated(
  eventService: EventService,
  payload: Omit<ExampleUpdatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.UPDATED, {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an example deleted event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload
 */
export async function emitExampleDeleted(
  eventService: EventService,
  payload: Omit<ExampleDeletedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.DELETED, {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an example status changed event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload
 */
export async function emitExampleStatusChanged(
  eventService: EventService,
  payload: Omit<ExampleStatusChangedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.STATUS_CHANGED, {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an example processed event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload
 */
export async function emitExampleProcessed(
  eventService: EventService,
  payload: Omit<ExampleProcessedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.PROCESSED, {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an item created event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload
 */
export async function emitItemCreated(
  eventService: EventService,
  payload: Omit<ItemCreatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.ITEM_CREATED, {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an item updated event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload
 */
export async function emitItemUpdated(
  eventService: EventService,
  payload: Omit<ItemUpdatedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.ITEM_UPDATED, {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits an item deleted event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload
 */
export async function emitItemDeleted(
  eventService: EventService,
  payload: Omit<ItemDeletedEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.ITEM_DELETED, {
    ...payload,
    timestamp: timestamp(),
  });
}

/**
 * Emits a bulk operation event.
 *
 * @param eventService - Event service instance
 * @param payload - Event payload
 */
export async function emitBulkOperation(
  eventService: EventService,
  payload: Omit<BulkOperationEventPayload, 'timestamp'>
): Promise<void> {
  await eventService.emitCustom(ADVANCED_EXAMPLE_EVENTS.BULK_OPERATION, {
    ...payload,
    timestamp: timestamp(),
  });
}

// -----------------------------------------------------------------------------
// Event Listener Helpers
// -----------------------------------------------------------------------------

/**
 * Type for event handler functions
 */
export type EventHandler<T> = (payload: T) => Promise<void> | void;

/**
 * Registers all example module event listeners.
 *
 * @param eventService - Event service instance
 * @param handlers - Object containing event handlers
 *
 * @example
 * ```typescript
 * registerExampleEventListeners(eventService, {
 *   onCreated: async (payload) => {
 *     console.log('Example created:', payload.exampleId);
 *   },
 *   onUpdated: async (payload) => {
 *     console.log('Example updated:', payload.exampleId);
 *   },
 * });
 * ```
 */
export function registerExampleEventListeners(
  eventService: EventService,
  handlers: {
    onCreated?: EventHandler<ExampleCreatedEventPayload>;
    onUpdated?: EventHandler<ExampleUpdatedEventPayload>;
    onDeleted?: EventHandler<ExampleDeletedEventPayload>;
    onStatusChanged?: EventHandler<ExampleStatusChangedEventPayload>;
    onProcessed?: EventHandler<ExampleProcessedEventPayload>;
    onItemCreated?: EventHandler<ItemCreatedEventPayload>;
    onItemUpdated?: EventHandler<ItemUpdatedEventPayload>;
    onItemDeleted?: EventHandler<ItemDeletedEventPayload>;
    onBulkOperation?: EventHandler<BulkOperationEventPayload>;
  }
): void {
  if (handlers.onCreated) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.CREATED, handlers.onCreated as (payload: unknown) => void);
  }
  if (handlers.onUpdated) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.UPDATED, handlers.onUpdated as (payload: unknown) => void);
  }
  if (handlers.onDeleted) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.DELETED, handlers.onDeleted as (payload: unknown) => void);
  }
  if (handlers.onStatusChanged) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.STATUS_CHANGED, handlers.onStatusChanged as (payload: unknown) => void);
  }
  if (handlers.onProcessed) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.PROCESSED, handlers.onProcessed as (payload: unknown) => void);
  }
  if (handlers.onItemCreated) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.ITEM_CREATED, handlers.onItemCreated as (payload: unknown) => void);
  }
  if (handlers.onItemUpdated) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.ITEM_UPDATED, handlers.onItemUpdated as (payload: unknown) => void);
  }
  if (handlers.onItemDeleted) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.ITEM_DELETED, handlers.onItemDeleted as (payload: unknown) => void);
  }
  if (handlers.onBulkOperation) {
    eventService.on(ADVANCED_EXAMPLE_EVENTS.BULK_OPERATION, handlers.onBulkOperation as (payload: unknown) => void);
  }
}

// -----------------------------------------------------------------------------
// Re-export Types
// -----------------------------------------------------------------------------

export type {
  ExampleCreatedEventPayload,
  ExampleUpdatedEventPayload,
  ExampleDeletedEventPayload,
  ExampleStatusChangedEventPayload,
  ExampleProcessedEventPayload,
};
